/*!
 * Chart.js v4.4.0
 * https://www.chartjs.org/
 * Simplified local build for CodePulse Campus
 */

window.Chart = class {

    constructor(
        context,
        configuration
    ) {

        this.context =
            context;

        this.configuration =
            configuration;

        this.canvas =
            context.canvas;

        this.render();
    }

    render() {

        const canvas =
            this.canvas;

        const ctx =
            this.context;

        const width =
            canvas.width =
                canvas.offsetWidth || 600;

        const height =
            canvas.height =
                canvas.offsetHeight || 300;

        ctx.clearRect(
            0,
            0,
            width,
            height
        );

        ctx.fillStyle =
            '#0f172a';

        ctx.fillRect(
            0,
            0,
            width,
            height
        );

        const data =
            this.configuration.data.datasets[0].data;

        const labels =
            this.configuration.data.labels;

        const maxValue =
            Math.max(...data);

        const barWidth =
            width / data.length;

        data.forEach(
            (
                value,
                index
            ) => {

                const barHeight =
                    (
                        value /
                        maxValue
                    ) *
                    (height - 80);

                ctx.fillStyle =
                    '#6366f1';

                ctx.fillRect(
                    index * barWidth + 20,
                    height - barHeight - 40,
                    barWidth - 40,
                    barHeight
                );

                ctx.fillStyle =
                    '#ffffff';

                ctx.font =
                    '12px Arial';

                ctx.fillText(
                    labels[index],
                    index * barWidth + 20,
                    height - 15
                );
            }
        );
    }
};